import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  addToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { UnitDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogFormFooter,
  CatalogListPagination,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogPageIntegration,
  SharedCatalogFormActions,
  sharedCatalogToolbarActions,
  CatalogDocumentHistory,
  CatalogListToolbar,
  CatalogListSelectionBanner,
  CatalogListGrid,
  CatalogRenameCodeModal,
  CatalogBatchDeleteModal,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { masterCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-don-vi-tinh';
const CATALOG_KIND = 'units';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const DonViTinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<UnitDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<UnitDto | null>(null);
  const [form, setForm] = useState<Partial<UnitDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [renameOpen, setRenameOpen] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [historyOpen, setHistoryOpen] = useState(false);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const selectableOnPage = items;

  const anchor = selection.singleAnchor;
  const canEditAnchor = !!anchor && !isSharedCatalogReadOnly(anchor);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getUnits({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({
              message: err instanceof Error ? err.message : 'Lỗi tải đơn vị tính',
              type: 'error',
            }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã đơn vị tính';
    if (!form.name?.trim()) next.name = 'Nhập tên đơn vị tính';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: UnitDto) => {
    setViewOnlyShared(isSharedCatalogReadOnly(row));
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
    void masterService.getUnit(row.id).then(full => {
      setEditing(full);
      setForm({ ...full });
    }).catch(() => { /* list row sufficient */ });
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateUnit(editing.id, {
          name: form.name!.trim(),
          isActive: form.isActive ?? true,
        });
      } else {
        await masterService.createUnit({
          code: normalizeCode(form.code!),
          name: form.name!.trim(),
        });
      }
      markClean();
      dispatch(addToast({
        message: editing ? 'Cập nhật đơn vị tính thành công' : 'Tạo đơn vị tính thành công',
        type: 'success',
      }));
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const resolveBatchIds = (): string[] => {
    if (selection.selectionMode === 'all') {
      return selectableOnPage.map(r => r.id);
    }
    return [...selection.selectedIds];
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids = resolveBatchIds().filter(id => {
      const row = items.find(r => r.id === id);
      return row && !isSharedCatalogReadOnly(row);
    });
    if (ids.length === 0) {
      throw new Error('Không có bản ghi hợp lệ để xóa');
    }
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id);
        return masterService.updateUnit(id, {
          name: row!.name,
          isActive: false,
        });
      }));
      dispatch(addToast({ message: `Đã ngưng ${ids.length} đơn vị tính`, type: 'success' }));
    } else {
      await Promise.all(ids.map(id => masterService.deleteUnit(id)));
      dispatch(addToast({ message: `Đã xóa ${ids.length} đơn vị tính`, type: 'success' }));
    }
    refresh();
  };

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <Input
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={e => setSearchDraft(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
        />
      </div>
      <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
    </>
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-ruler" /> Danh mục đơn vị tính
          </h1>
        </div>
      </div>

      <CatalogListToolbar
        testIdPrefix={TEST_ID}
        selectedCount={selection.selectedCount}
        canAdd
        canEdit={canEditAnchor}
        canHistory={!!anchor}
        canRename={canEditAnchor}
        canDelete={selection.selectedCount > 0 && selectableOnPage.some(r => selection.isRowChecked(r))}
        sharedActions={sharedCatalogToolbarActions(
          TEST_ID,
          CATALOG_KIND,
          shared,
          anchor
            ? {
                code: anchor.code,
                name: anchor.name,
                isActive: anchor.isActive,
                isReadOnly: anchor.isReadOnly,
                scope: anchor.scope,
              }
            : null,
        )}
        onAdd={openAdd}
        onEdit={() => anchor && openEdit(anchor)}
        onHistory={() => setHistoryOpen(true)}
        onRefresh={refresh}
        onRename={() => setRenameOpen(true)}
        onDelete={() => setDeleteOpen(true)}
      />

      <CatalogListSelectionBanner
        testIdPrefix={TEST_ID}
        selectedCount={selection.selectedCount}
        totalCount={totalCount}
        selectionMode={selection.selectionMode}
        pageSelectableCount={selectableOnPage.length}
        onSelectAllDatabase={selection.selectAllInDatabase}
        onClear={selection.clearSelection}
      />

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách đơn vị tính"
        showTableLoading={showTableLoading}
        filters={filterBar}
        footer={
          <SharedCatalogPageIntegration
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            pagination={
              <CatalogListPagination
                testIdPrefix={TEST_ID}
                page={page}
                totalCount={totalCount}
                pageSize={pageSize}
                onPageChange={p => { setPage(p); selection.clearSelection(); }}
                onPageSizeChange={setPageSize}
              />
            }
          />
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy đơn vị tính phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={() => true}
            headerCells={(
              <>
                <th>Mã</th>
                <th>Tên</th>
                <CatalogCompanyTh />
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => (
              <>
                <td><code>{r.code}</code></td>
                <td>{r.name}</td>
                <CatalogCompanyTd label={r.companyName} />
                <td>
                  <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                    {r.isActive ? 'Hoạt động' : 'Ngưng'}
                  </span>
                </td>
              </>
            )}
          />
        )}
      </CatalogListShell>

      {anchor && (
        <CatalogDocumentHistory
          testIdPrefix={TEST_ID}
          documentType={masterCatalogDocumentTypes.units}
          documentId={anchor.id}
          documentCode={anchor.code}
          variant="inline"
          isOpen={historyOpen}
          onClose={() => setHistoryOpen(false)}
        />
      )}

      {anchor && (
        <CatalogRenameCodeModal
          testIdPrefix={TEST_ID}
          isOpen={renameOpen}
          onClose={() => setRenameOpen(false)}
          catalogKind={CATALOG_KIND}
          oldCode={anchor.code}
          oldName={anchor.name}
          onSubmit={async () => {
            dispatch(addToast({
              message: 'Đổi mã + job replace — BE phase 2 (usage-impact registry)',
              type: 'info',
            }));
          }}
        />
      )}

      <CatalogBatchDeleteModal
        testIdPrefix={TEST_ID}
        isOpen={deleteOpen}
        onClose={() => setDeleteOpen(false)}
        selectedCount={selection.selectedCount}
        catalogKind={CATALOG_KIND}
        fetchDeleteImpact={async () => ({
          canRemove: true,
          impact: [],
        })}
        onConfirm={handleBatchDelete}
      />

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem đơn vị tính dùng chung' : editing ? 'Sửa đơn vị tính' : 'Thêm đơn vị tính'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã đơn vị tính *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên đơn vị tính *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{ name: form.name, isActive: form.isActive }}
            {...sharedForm}
          />
          {viewOnlyShared ? (
            <div className={styles.modalActions}>
              <CatalogDocumentHistory
                testIdPrefix={TEST_ID}
                documentType={masterCatalogDocumentTypes.units}
                documentId={editing?.id}
                documentCode={editing?.code}
              />
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
              historySlot={
                editing ? (
                  <CatalogDocumentHistory
                    testIdPrefix={TEST_ID}
                    documentType={masterCatalogDocumentTypes.units}
                    documentId={editing.id}
                    documentCode={editing.code}
                  />
                ) : null
              }
            />
          )}
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </div>
  );
};

export default DonViTinhPage;
